import React, { useState } from 'react';
import axios from 'axios';
import { TextField, Button, Typography, Grid, Card, CardContent, Box, Alert, CircularProgress, Chip, Avatar, Divider } from '@mui/material';
import { Dashboard, Person, Search, Delete, Analytics, TrendingUp, AccessTime, People } from '@mui/icons-material';

const AdminDashboard = () => {
    const [personId, setPersonId] = useState('');
    const [person, setPerson] = useState(null);
    const [metrics, setMetrics] = useState(null);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [severity, setSeverity] = useState('success');

    const fetchPerson = async () => {
        if (!personId) return;
        setLoading(true);
        setMessage('');
        try {
            const response = await axios.get(`/api/persons/${personId}`);
            setPerson(response.data);
            setMessage('Person fetched successfully');
            setSeverity('success');
        } catch (error) {
            console.error('Failed to fetch person');
            setMessage('Failed to fetch person. Please check the ID.');
            setSeverity('error');
        }
        setLoading(false);
    };

    const deletePerson = async () => {
        if (!personId) return;
        setLoading(true);
        setMessage('');
        try {
            await axios.delete(`/api/persons/${personId}`);
            setPerson(null);
            setMessage('Person deleted successfully');
            setSeverity('success');
        } catch (error) {
            console.error('Failed to delete person');
            setMessage('Failed to delete person. Please try again.');
            setSeverity('error');
        }
        setLoading(false);
    };

    const fetchMetrics = async () => {
        setLoading(true);
        setMessage('');
        try {
            const response = await axios.get('/api/metrics');
            setMetrics(response.data);
            setMessage('Metrics fetched successfully');
            setSeverity('success');
        } catch (error) {
            console.error('Failed to fetch metrics');
            setMessage('Failed to fetch metrics. Please try again.');
            setSeverity('error');
        }
        setLoading(false);
    };

    return (
        <Box sx={{ maxWidth: 1200, mx: 'auto' }}>
            <Typography variant="h5" gutterBottom sx={{ mb: 4, textAlign: 'center', fontWeight: 600 }}>
                <Dashboard sx={{ mr: 1, verticalAlign: 'middle' }} />
                Admin Dashboard
            </Typography>

            <Grid container spacing={4}>
                {/* Person Management Section */}
                <Grid item xs={12} lg={6}>
                    <Card sx={{ p: 4, height: '100%' }}>
                        <CardContent>
                            <Typography variant="h6" gutterBottom sx={{ mb: 3, fontWeight: 600 }}>
                                <Person sx={{ mr: 1, verticalAlign: 'middle' }} />
                                Person Management
                            </Typography>

                            <Grid container spacing={2}>
                                <Grid item xs={12}>
                                    <TextField
                                        fullWidth
                                        label="Person ID"
                                        variant="outlined"
                                        value={personId}
                                        onChange={(e) => setPersonId(e.target.value)}
                                        sx={{ mb: 2 }}
                                    />
                                </Grid>

                                <Grid item xs={6}>
                                    <Button
                                        fullWidth
                                        variant="contained"
                                        onClick={fetchPerson}
                                        disabled={loading || !personId}
                                        sx={{
                                            py: 1.5,
                                            fontWeight: 600,
                                            borderRadius: '12px',
                                            background: 'linear-gradient(45deg, #00bcd4 30%, #ff4081 90%)',
                                            '&:hover': {
                                                background: 'linear-gradient(45deg, #00bcd4 50%, #ff4081 100%)',
                                                transform: 'translateY(-2px)',
                                            },
                                            '&:disabled': {
                                                background: 'rgba(255, 255, 255, 0.1)',
                                                color: 'rgba(255, 255, 255, 0.3)',
                                            }
                                        }}
                                        startIcon={<Search />}
                                    >
                                        Get Person
                                    </Button>
                                </Grid>

                                <Grid item xs={6}>
                                    <Button
                                        fullWidth
                                        variant="outlined"
                                        color="error"
                                        onClick={deletePerson}
                                        disabled={loading || !personId}
                                        sx={{
                                            py: 1.5,
                                            fontWeight: 600,
                                            borderRadius: '12px',
                                            borderColor: '#ff4081',
                                            color: '#ff4081',
                                            '&:hover': {
                                                borderColor: '#ff4081',
                                                background: 'rgba(255, 64, 129, 0.1)',
                                                transform: 'translateY(-2px)',
                                            },
                                            '&:disabled': {
                                                borderColor: 'rgba(255, 255, 255, 0.1)',
                                                color: 'rgba(255, 255, 255, 0.3)',
                                            }
                                        }}
                                        startIcon={<Delete />}
                                    >
                                        Delete Person
                                    </Button>
                                </Grid>
                            </Grid>

                            {person && (
                                <Box sx={{ mt: 3 }}>
                                    <Divider sx={{ mb: 2 }} />
                                    <Typography variant="h6" gutterBottom sx={{ fontWeight: 600 }}>
                                        Person Details
                                    </Typography>
                                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                                        <Avatar sx={{ mr: 2, bgcolor: '#00bcd4' }}>
                                            <Person />
                                        </Avatar>
                                        <Box>
                                            <Typography variant="body1" sx={{ fontWeight: 600 }}>
                                                {person.name}
                                            </Typography>
                                            <Typography variant="body2" sx={{ color: 'text.secondary' }}>
                                                ID: {person.person_id}
                                            </Typography>
                                        </Box>
                                    </Box>
                                    <Chip
                                        label={`${person.embeddings.length} Embeddings`}
                                        color="primary"
                                        sx={{
                                            fontSize: '0.9rem',
                                            fontWeight: 600,
                                            px: 2,
                                            py: 1,
                                            borderRadius: '12px',
                                        }}
                                    />
                                </Box>
                            )}
                        </CardContent>
                    </Card>
                </Grid>

                {/* Metrics Section */}
                <Grid item xs={12} lg={6}>
                    <Card sx={{ p: 4, height: '100%' }}>
                        <CardContent>
                            <Typography variant="h6" gutterBottom sx={{ mb: 3, fontWeight: 600 }}>
                                <Analytics sx={{ mr: 1, verticalAlign: 'middle' }} />
                                System Metrics
                            </Typography>

                            <Button
                                fullWidth
                                variant="contained"
                                onClick={fetchMetrics}
                                disabled={loading}
                                sx={{
                                    py: 1.5,
                                    mb: 3,
                                    fontWeight: 600,
                                    borderRadius: '12px',
                                    background: 'linear-gradient(45deg, #00bcd4 30%, #ff4081 90%)',
                                    '&:hover': {
                                        background: 'linear-gradient(45deg, #00bcd4 50%, #ff4081 100%)',
                                        transform: 'translateY(-2px)',
                                    },
                                    '&:disabled': {
                                        background: 'rgba(255, 255, 255, 0.1)',
                                        color: 'rgba(255, 255, 255, 0.3)',
                                    }
                                }}
                                startIcon={loading ? <CircularProgress size={20} /> : <TrendingUp />}
                            >
                                Fetch Metrics
                            </Button>

                            {metrics && (
                                <Box>
                                    <Divider sx={{ mb: 2 }} />
                                    <Grid container spacing={2}>
                                        <Grid item xs={12} sm={6}>
                                            <Card sx={{
                                                p: 2,
                                                background: 'linear-gradient(145deg, rgba(0, 188, 212, 0.1), rgba(255, 64, 129, 0.05))',
                                                border: '1px solid rgba(0, 188, 212, 0.3)',
                                                borderRadius: '12px',
                                                textAlign: 'center',
                                            }}>
                                                <People sx={{ fontSize: '2rem', color: '#00bcd4', mb: 1 }} />
                                                <Typography variant="h6" sx={{ fontWeight: 600 }}>
                                                    {metrics.recognition_count}
                                                </Typography>
                                                <Typography variant="body2" sx={{ color: 'text.secondary' }}>
                                                    Recognitions
                                                </Typography>
                                            </Card>
                                        </Grid>

                                        <Grid item xs={12} sm={6}>
                                            <Card sx={{
                                                p: 2,
                                                background: 'linear-gradient(145deg, rgba(0, 188, 212, 0.1), rgba(255, 64, 129, 0.05))',
                                                border: '1px solid rgba(0, 188, 212, 0.3)',
                                                borderRadius: '12px',
                                                textAlign: 'center',
                                            }}>
                                                <Person sx={{ fontSize: '2rem', color: '#ff4081', mb: 1 }} />
                                                <Typography variant="h6" sx={{ fontWeight: 600 }}>
                                                    {metrics.enroll_count}
                                                </Typography>
                                                <Typography variant="body2" sx={{ color: 'text.secondary' }}>
                                                    Enrollments
                                                </Typography>
                                            </Card>
                                        </Grid>

                                        <Grid item xs={12}>
                                            <Card sx={{
                                                p: 2,
                                                background: 'linear-gradient(145deg, rgba(0, 188, 212, 0.1), rgba(255, 64, 129, 0.05))',
                                                border: '1px solid rgba(0, 188, 212, 0.3)',
                                                borderRadius: '12px',
                                                textAlign: 'center',
                                            }}>
                                                <AccessTime sx={{ fontSize: '2rem', color: '#00bcd4', mb: 1 }} />
                                                <Typography variant="h6" sx={{ fontWeight: 600 }}>
                                                    {metrics.avg_latency_ms} ms
                                                </Typography>
                                                <Typography variant="body2" sx={{ color: 'text.secondary' }}>
                                                    Average Latency
                                                </Typography>
                                            </Card>
                                        </Grid>
                                    </Grid>
                                </Box>
                            )}
                        </CardContent>
                    </Card>
                </Grid>

                {message && (
                    <Grid item xs={12}>
                        <Alert
                            severity={severity}
                            sx={{
                                borderRadius: '16px',
                                fontSize: '1rem',
                                '& .MuiAlert-icon': {
                                    fontSize: '1.5rem',
                                }
                            }}
                        >
                            {message}
                        </Alert>
                    </Grid>
                )}
            </Grid>
        </Box>
    );
};

export default AdminDashboard;
